const incoming = $input.first()?.json ?? {};
const body = incoming.body ?? incoming;

const courseName = body.course_name || body.courseName || "Unknown Course";
const courseId = body.course_id || body.courseId || "course_unknown";
const materials = Array.isArray(body.materials) ? body.materials : [];

const normalizedMaterials = materials.map((m, index) => ({
  source_id: m.source_id || m.sourceId || `src_${String(index + 1).padStart(3, "0")}`,
  file_name: m.file_name || m.fileName || m.name || `material_${index + 1}`,
  source_type: m.source_type || m.sourceType || "unknown",
  text: m.text || m.content || "",
  page_start: m.page_start || m.pageStart || null,
  page_end: m.page_end || m.pageEnd || null,
  metadata: m.metadata || {}
}));

return [{
  json: {
    workflow_name: "course_material_agent",
    course_id: courseId,
    course_name: courseName,
    material_summary: {
      total_files: normalizedMaterials.length,
      file_types: [...new Set(normalizedMaterials.map(m => m.source_type))],
      file_names: normalizedMaterials.map(m => m.file_name)
    },
    materials: normalizedMaterials,
    constraints: {
      no_exam_prediction: true,
      no_final_priority_decision: true,
      evidence_required_for_each_concept: true
    }
  }
}];

const data = $input.first().json;

const materialPreview = (data.materials || []).map(m => ({
  source_id: m.source_id,
  file_name: m.file_name,
  source_type: m.source_type,
  page_start: m.page_start,
  page_end: m.page_end,
  metadata: m.metadata,
  text: (m.text || "").slice(0, 6000)
}));

const systemPrompt = `You are Course Material Agent in CourseLens, a multi-agent course review system.

Your only job is to build a structured Course Knowledge Map from course materials.

Tool policy:
- A placeholder calculator tool may be connected for n8n agent-node compatibility.
- Do not call any tool unless absolutely necessary.
- For this workflow, solve the task directly from the provided materials.

Rules:
1. Extract course content only: chapters, topics, concepts, definitions, formulas, algorithms, methods, examples, and prerequisite relations.
2. Every concept must include source evidence from the provided materials.
3. Do not predict exam questions.
4. Do not say any concept is "must-test", "guaranteed", or "certainly examined".
5. Do not generate a review plan.
6. Do not analyze student weaknesses.
7. If evidence is weak or missing, put the issue in uncertainties.
8. Return valid JSON only. Do not wrap it in Markdown. Do not add explanations outside JSON.`;

const userPrompt = `Build a Course Knowledge Map for the course below.

Course ID: ${data.course_id}
Course name: ${data.course_name}

Material summary:
${JSON.stringify(data.material_summary, null, 2)}

Materials:
${JSON.stringify(materialPreview, null, 2)}

Return this exact JSON shape:
{
  "workflow_name": "course_material_agent",
  "course_id": "${data.course_id}",
  "course_name": "${data.course_name}",
  "material_summary": {
    "total_files": number,
    "file_types": ["string"],
    "file_names": ["string"],
    "covered_chapters": ["string"]
  },
  "knowledge_map": [
    {
      "chapter": "string",
      "topics": [
        {
          "topic_name": "string",
          "concepts": [
            {
              "concept_id": "stable short id such as c_001",
              "concept_name": "string",
              "concept_type": "definition | formula | algorithm | method | comparison | example | theorem | process | application",
              "summary": "string",
              "source_evidence": [
                {
                  "source_id": "string",
                  "file_name": "string",
                  "page": number_or_null,
                  "evidence_text": "short direct evidence from the material"
                }
              ],
              "related_concepts": ["string"],
              "material_coverage": "low | medium | high"
            }
          ]
        }
      ]
    }
  ],
  "dependency_relations": [
    {
      "from": "concept name or concept_id",
      "to": "concept name or concept_id",
      "relation": "prerequisite | extension | contrast | application"
    }
  ],
  "uncertainties": ["string"]
}

Quality requirements:
- Prefer concise but meaningful summaries.
- Use source_id and file_name exactly as given.
- Use page_start as page when no more specific page is available.
- If the material is too short to infer chapters, create a reasonable chapter label and mark it in uncertainties.
- Keep evidence_text short.`;

return [{
  json: {
    ...data,
    llm_payload: {
      system_prompt: systemPrompt,
      user_prompt: userPrompt
    }
  }
}];

const llmResult = $input.first().json;

function pickRawOutput(value) {
  if (typeof value === "string") return value;
  if (value?.output !== undefined) return value.output;
  if (value?.response?.text !== undefined) return value.response.text;
  if (value?.generations?.[0]?.[0]?.text !== undefined) return value.generations[0][0].text;
  if (value?.choices?.[0]?.message?.content !== undefined) return value.choices[0].message.content;
  if (value?.text !== undefined) return value.text;
  if (value?.response !== undefined) return value.response;
  if (value?.message?.content !== undefined) return value.message.content;
  return value;
}

function stripCodeFence(text) {
  return text
    .replace(/^```(?:json)?\s*/i, "")
    .replace(/\s*```$/i, "")
    .trim();
}

function parseJsonLoose(raw) {
  if (raw && typeof raw === "object") {
    if (raw.workflow_name || raw.knowledge_map) return raw;
    raw = JSON.stringify(raw);
  }

  let text = String(raw ?? "").trim();
  text = stripCodeFence(text);

  try {
    return JSON.parse(text);
  } catch (firstError) {
    const start = text.indexOf("{");
    const end = text.lastIndexOf("}");
    if (start >= 0 && end > start) {
      const candidate = text.slice(start, end + 1);
      return JSON.parse(candidate);
    }
    throw firstError;
  }
}

let parsed;
try {
  parsed = parseJsonLoose(pickRawOutput(llmResult));
} catch (error) {
  return [{
    json: {
      workflow_name: "course_material_agent",
      parser_error: true,
      error_message: error.message,
      raw_llm_output: llmResult
    }
  }];
}

parsed.workflow_name = parsed.workflow_name || "course_material_agent";
parsed.material_summary = parsed.material_summary || {};
parsed.knowledge_map = Array.isArray(parsed.knowledge_map) ? parsed.knowledge_map : [];
parsed.dependency_relations = Array.isArray(parsed.dependency_relations) ? parsed.dependency_relations : [];
parsed.uncertainties = Array.isArray(parsed.uncertainties) ? parsed.uncertainties : [];
parsed._agent_meta = {
  parsed_at: new Date().toISOString(),
  node: "Parse OpenAI JSON"
};

return [{ json: parsed }];
